def check_applause_countries(countries):
    top_applause_countries = {'Greece', 'Hungary', 'Lebanon', 'Spain'}
    return any(country in top_applause_countries for country in countries)

# Example usage:
print(check_applause_countries(['USA', 'Canada', 'Greece']))  # Output: True
print(check_applause_countries(['France', 'UK', 'Australia']))  # Output: False
